window.MUDA_CASES = [{"id":"CT-3017","l":"iru","k":"機械加工","s":"旋盤","n":"CT・バラつきの低減","t":"CT改善","y":276000,"d":"加工後のワークを一時仮置きしてから、次の工程に進んでいたので、ワーク搬送シュートを設置し、仮置き作業を無くした。結果、CT36.4sからCT34.7s、1.7s/回短縮することができ、年間で276,000円労務費削減出来ました。"},{"id":"CT-4010","l":"iru","k":"検査工程","s":"検査治具","n":"CTバラつきの削減","t":"CT改善","y":136000,"d":"検査後の箱詰め時にカウンターを押す手間があったため、ゲージにセットするだけで自動カウントされるように改善しました。結果、840秒/日短縮、年間で136,000円労務費削減できました。"},{"id":"CT-4016","l":"iru","k":"機械加工・人","s":"マシニング・手作業","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":251400,"d":"サイクルタイムのバラツキが大きい。加工バリの出方や大きさによりバリ取り作業時間に違いが発生。赤丸部の加工を廃止しバリ取り作業を無くしました。作業時間が8秒/回から6.2秒/回に短縮出来ました。日当たりで26分稼働時間が短縮でき、年間で251,400円労務費削減出来ました。"},{"id":"CT-4030","l":"iru","k":"機械加工","s":"マシニング","n":"マシンタイム短縮","t":"CT改善","y":243000,"d":"刃具折れ検知の頻度が高く、加工のたびに設備が停止し確認作業が発生していた。エンジニアと相談し、製品や加工条件に応じて検知回数・タイミングを最適化。不要な停止を削減しました。結果、1,500秒/日短縮、243,000円労務費削減できました"},{"id":"CT-4038","l":"iru","k":"手作業","s":"人","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":29232,"d":"作業者の手作業が多く、人がネック工程となっていました。エアーブローをせずに洗浄工程のみでも加工で付着した切粉を除去出来る事から、エアーブロー工程での手作業を廃止しました。手作業時間は64.4秒/回から62.9秒/回に短縮出来ました。日当たりで3分稼働時間が短縮でき、年間29,232円労務費削減出来ました。"},{"id":"CT-5001","l":"iru","k":"機械加工","s":"マシニング","n":"CT短縮","t":"CT改善","y":146000,"d":"作業者から困り事として、箱詰め前の全数検査工程を無くしたいと相談があったので、エンジニアに依頼し、次工程の治具で検査ができるようにした。結果、900ｓ/日短縮、年間で146,000円労務費削減できました。"},{"id":"CT-5003","l":"iru","k":"外観検査","s":"","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":272000,"d":"不良が出ないのであればゲージでの確認をやめることができるのではないか、品質保証部、エンジニアリング部、製造部で協議を重ね、曲がりゲージを廃止。CTを0.2秒縮めることができ、年間272,000円の労務費を削減。"},{"id":"CT-5004","l":"iru","k":"手作業","s":"人","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":116928,"d":"サイクルタイムのバラつきが大きい。確認してみると、本来不必要な作業を実施していた。自工程でのバリ除去作業を廃止し、前工程で品質を保証。作業時間が12.2秒/回短縮でき、日当たりで12分稼働時間が短縮。年間116,928円労務費削減出来ました。"},{"id":"CT-5013","l":"iru","k":"検査","s":"画像検査機","n":"CTバラつきの削減","t":"CT改善","y":156000,"d":"識別チェックを行うのが大変なので“全数検査工程”を無くすことができないかという困り事相談があったので、不良検知を行える画像検査機を導入し、人が目視で行っていた検査作業を無くし、カメラを使用した画像検査機に変更しました。結果、960秒/日短縮、年間で156,000円労務費削減できました。"},{"id":"可動-1052","l":"iru","k":"組付","s":"組付機","n":"可動率改善","t":"可動率改善","y":19200,"d":"遊休のスライドコンベアを利用して組付作業者の箱返し作業を廃止したことにより、設備停止時間が日当たり２分短縮、年間19,200円の労務費削減ができた｡"},{"id":"可動-1056","l":"iru","k":"機械加工","s":"旋盤","n":"設備停止の削減","t":"可動率改善","y":117000,"d":"小容量ジョッキで給油時に往復が多く時間ロスと負担が発生していた。そこで、必要量を一度で運べる大容量ジョッキに変更し効率化した。結果、12分削減、年間117,000円労務費削減できました"},{"id":"可動-1057","l":"iru","k":"","s":"","n":"","t":"可動率改善","y":585000,"d":"不純物を沈静させるのに30分かけていた。沈静時間を無くしても介在物が出ない為、沈静時間を廃止した。フラックス時間が30分短縮し、日当たりで1時間。年間効果金額は585,000円の労務費低減が出来ました。"},{"id":"可動-1058","l":"iru","k":"","s":"","n":"","t":"可動率改善","y":585000,"d":"不純物を沈静させるのに30分かけていた。沈静時間を無くしても介在物が出ない為、沈静時間を廃止した。フラックス時間が30分短縮し、日当たりで1時間。年間効果金額は585,000円の労務費低減が出来ました。"},{"id":"可動-1062","l":"iru","k":"切断･面取り","s":"切断･旋盤機","n":"箱替え作業時間短縮","t":"可動率改善","y":0,"d":"無駄なダブり作業を廃止し、作業順序を見直したことで付帯作業時間を短縮。設備稼働時間が0.83分短縮し、年間で8,000円の労務費削減ができた｡"},{"id":"可動-1076","l":"iru","k":"段取り替え","s":"プレス","n":"停止の削減","t":"可動率改善","y":0,"d":"プレス前で台車の高さ調整に時間がかかっていたため、目安線を引いて調整不要にした。外段取り化により、段取り替え時間を短縮することができた。結果、60ｓ/日削減できました。"},{"id":"可動-1083","l":"iru","k":"段取り替え","s":"ハンマー","n":"","t":"可動率改善","y":0,"d":"圧型取付時、上下のコッターを仮打ちし、エアードロップハンマーを踏みながら再度打ち込んでいたため、作業に時間がかかっていた。そこで、上下のコッターを挿入後、エアードロップハンマーで打ち込むことで、仮打ち作業を廃止。結果、70ｓ/日削減できました"},{"id":"可動-2008","l":"iru","k":"機械加工","s":"専用機","n":"停止の削減","t":"可動率改善","y":31000,"d":"治具固定のボルトの取り外しに時間が掛かっていた。四隅を二隅に留めるように変更し、ボルトの数を減らした。結果、3.2分/日短縮、年間、31,000円労務費削減できました。"},{"id":"可動-2020","l":"iru","k":"研磨","s":"研磨機","n":"砥石交換時間低減","t":"可動率改善","y":19200,"d":"研磨機に合う砥石とクーラント液に変更｡砥石の持ちが1ヶ月から1.5ヶ月になり、50%向上。併せて砥石交換工数も月50%低減､月120分→月80分に低減できた｡設備停止時間が40分/月短くなり年間で19,200円の労務費削減ができた｡"},{"id":"可動-2038","l":"iru","k":"鍛造工程","s":"エアードロップハンマー","n":"停止時間の削減","t":"可動率改善","y":110000,"d":"本当にやらないといけないの？と言う視点から他部署を巻き込み本来やらなくてもよい事を廃止した。その結果過剰品質が無くなり日当たり11分の停止時間が無くなり、年間で110,000円の労務費削減出来ました。"},{"id":"可動-2039","l":"iru","k":"品質チェック","s":"品質チェック","n":"設備停止の削減","t":"可動率改善","y":97500,"d":"品質チェックで重要度の低い項目も毎回確認・記録していたため、作業時間が長くなっていた。そこで、品質保証部と確認し、不要項目を廃止することで、作業時間を短縮。結果、10分削減、年間97,500円労務費削減できました。"},{"id":"可動-2047","l":"iru","k":"粗材","s":"人","n":"停止の削減","t":"可動率改善","y":165000,"d":"粗材箱を手動で補充していたため、作業者が移動や運搬に時間を取られていた。そこで自働供給の仕組みに変更し、補充作業を不要にした。結果、17分/日削減、年間165,000円労務費削減できました。"},{"id":"可動-2049","l":"iru","k":"組付","s":"組付機","n":"完成品投入作業廃止","t":"可動率改善","y":195000,"d":"完成品ストア投入作業を人から自動搬送機へ変更することにより、設備稼働時間が20分短くなり年間で195,000円の労務費削減ができた｡"},{"id":"CT-3038","l":"machi","k":"外観検査機","s":"材料供給装置","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":1042800,"d":"パーツフィーダ内ボール表面材質を目の細かいものに変更､製品の滑りを良くしたことで材料の供給遅れを無くし､サイクルタイムの遅れを解消。設備稼働時間が107分短くなり年間で1,042,800円の労務費削減ができた｡"},{"id":"CT-4028","l":"machi","k":"洗浄工程","s":"洗浄機","n":"CTバラつきの削減","t":"CT改善","y":406000,"d":"洗浄工程で圧力が安定せず時間がかかっていた。調査の結果、空気混入による逆流が原因と判明。配管にチェックバルブを設置し逆流を防止。圧力が安定し、洗浄時間は10秒から5秒に短縮できた。結果、2,500秒/日短縮、年間で406,000円労務費削減できました"},{"id":"CT-4033","l":"machi","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":81000,"d":"刃物の動作を確認したところ、固定サイクルによる無駄な動きや不要な停止が発生していた。そこで、加工プログラムを通常サイクルに変更し、切削開始から原点復帰までの無駄を排除することで、効率的な動作に改善した。結果、500秒/日短縮、年間で81,000円労務費削減できました。"},{"id":"CT-4034","l":"machi","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":32500,"d":"動作に無駄がありプログラムを確認したところ、不要な行や空白行が含まれていた。そこで、それらを削除し、無駄な停止や動きを防止。プログラムを最適化することで、スムーズな加工動作を実現した。結果、200秒/日短縮、年間で32,500円労務費削減できました"},{"id":"CT-4035","l":"machi","k":"切断･面取り","s":"切断･切削機","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":390000,"d":"設備内刃物ホルダー刃物の位置を変更､無駄な動作をなくすことで0.5秒のサイクルタイムを短縮し、設備稼働時間が40分短縮。年間390,000円の労務費削減ができた｡"},{"id":"CT-4036","l":"machi","k":"機械加工","s":"マシニング","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":38976,"d":"マシンがネック工程となっている為確認すると、刃物を6本使用しており、刃物の並び順が加工の順番になっていない為、無駄な距離を移動し刃物を交換していた。加工の順番通りに刃物を並び替えた結果、無駄な移動をせずに刃具交換でき、サイクルタイムは1.0秒短縮出来ました。日当たり4分稼働時間が短縮でき、年間38,976円労務費削減出来ました。"},{"id":"CT-4039","l":"machi","k":"機械加工","s":"専用機","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":175392,"d":"マシンがネック工程となっている為確認すると、専用機の一つの加工ユニットが他のユニットに比べ遅い事が分かりました。マシンタイムを短縮する為に第2原点を新たに設け、加工完了後のユニットが戻る位置をワークに近づけ移動する距離を短くしました。ネック工程の改善を行った結果、サイクルタイムは1.0秒短縮出来ました。日当たり18分稼働時間を短縮でき、年間175,392円労務費削減出来ました。"},{"id":"CT-4042","l":"machi","k":"アルミ鋳造","s":"高速ダイカストマシン","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":292392,"d":"ロボットが製品を取るのに待っていた型が開くまでの時間のタイマーを短縮し、1個当たり2秒短縮。日当たり30分、年間292,000円労務費削減出来ました。"},{"id":"CT-4043","l":"machi","k":"機械加工","s":"専用機","n":"サイクルタイム短縮","t":"CT改善","y":194000,"d":"テーブルクランプの閉め確認タイマー時間が必要以上に長いので、タイマー時間を短くしました。2ｓ/回→0.5ｓ/回に短縮。サイクルタイム1.5s/回短縮、1,200ｓ/日短縮でき、年間で194,000円労務費低減できました。"},{"id":"CT-4044","l":"machi","k":"機械加工","s":"専用機","n":"サイクルタイム短縮","t":"CT改善","y":194000,"d":"設備内のテーブルクランプ開き確認タイマーが長く、無駄が発生していた。そこで、タイマー時間を2秒から0.5秒に短縮することで、サイクルタイムの改善を図りました。結果、サイクルタイム1.5s/回短縮、1,200秒/日短縮でき、年間で194,000円労務費削減できました。"},{"id":"CT-4051","l":"machi","k":"溶接","s":"自動溶接機","n":"待ちの削減","t":"サイクルタイム改善","y":1000000,"d":"1サイクル停止から再始動までの間隔が長かった為、設備プログラム見直し更新し待ちの削減を図る。設備稼働時間が日当たりで112分短縮。年間1,000,000円の労務費削減できた｡"},{"id":"CT-4052","l":"machi","k":"全長切削搬機","s":"材料搬送装置","n":"サイクルタイムの短縮","t":"サイクルタイム短縮改善","y":351000,"d":"カメラでの判別時間を調べたところ0.5秒のタイマーが入っていました。タイマーを0.2秒短縮。結果、サイクルタイムも3.5秒➨3.3秒となり、結果として､設備稼働時間を36分短縮｡労務費効果として月当たり29,000円、年当たり351,000円の金額効果が得られました。"},{"id":"CT-4053","l":"machi","k":"機械加工","s":"マシニング","n":"CT短縮","t":"CT改善","y":81000,"d":"クランプ動作後、確認タイマーが長く設定されていたため設備が待機し、無駄な時間が発生していた。タイマーを必要最小限に短縮。クランプ完了と同時に次の動作へ進めるようにした。結果、500秒/日短縮、年間で81,000円労務費削減できました。"},{"id":"CT-4054","l":"machi","k":"機械加工","s":"マシニング","n":"CT短縮","t":"CT改善","y":81000,"d":"アンクランプ動作完了後も確認タイマーが長く、設備が次工程に進めず無駄な待機時間が発生していた。タイマー設定を必要最小限に短縮。動作完了と同時に次工程へ移行できるようにした。結果、500秒/日短縮、年間で81,000円労務費削減できました。"},{"id":"CT-4060","l":"machi","k":"溶接","s":"自動溶接機","n":"サイクルタイム短縮","t":"サイクルタイム短縮改善","y":1356000,"d":"ロボットの待機位置をプログラム変更し､ぎりぎりまで近づけるなどをして1.9秒のサイクルタイムを短縮。設備稼働時間が日当たり139分短縮、年間1,356,000円の労務費削減ができた｡"},{"id":"CT-4062","l":"machi","k":"機械加工","s":"旋盤","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":175392,"d":"マシンがネック工程となっている為、加工設備である旋盤の加工条件の見直しを実施しました。設定主軸回転数を3000rpmから2000rpmへ変更した事により、正味加工時間は遅くなりましたが、設定回転数到達時間と主軸停止時間が速くなり、マシンタイムとして5秒/回短縮し、サイクルタイムは0.7秒短縮出来ました。日当たり18分稼働時間が短縮でき、年間175,392円労務費削減出来ました。"},{"id":"CT-5010","l":"machi","k":"機械加工","s":"マシニング","n":"CT短縮","t":"CT改善","y":146000,"d":"1工程と2工程が同じ設備で同じ加工製品であるにも関わらず、2工程目のマシンタイムが長くなっており、手待ちが発生。そこで、2工程のマシンタイムを1工程のマシンタイムに合わせ、プログラム変更を行い、短くした。結果、900ｓ/日短縮、年間で146,000円労務費削減できました。"},{"id":"可動-1078","l":"machi","k":"段替え","s":"電気炉","n":"停止の削減","t":"可動率改善","y":20000,"d":"型のセット後に加熱を始めていたため、径の大きい材料は加熱に時間がかかり段替えが長引いていた。そこで、型のセット途中から加熱を始めることで、加熱待ち時間を短縮できた。結果、2分/日削減、年間20,000円労務費削減できました。"},{"id":"可動-2041","l":"machi","k":"品質チェック","s":"付帯作業","n":"設備停止の削減","t":"可動率改善","y":292000,"d":"定期品質チェック時、作業者やロボットが早めに待機し、無駄な時間が発生していた。スマートウォッチへ通知する仕組みを導入。待機時間をなくし、作業効率を向上させた。結果、30分/日削減、年間292,000円労務費削減できました。"},{"id":"可動-2055","l":"machi","k":"洗浄工程","s":"洗浄機","n":"付帯作業時間の削減","t":"可動率改善","y":195000,"d":"設備の電源を手動起動しているため、待ち時間が発生していた。そこで、エンジの助言でカレンダータイマーを設置し、始業前に自動起動して待ち時間を解消した。結果、20分/日削減、年間195,000円労務費削減できました。"},{"id":"可動-2056","l":"machi","k":"外観検査","s":"","n":"停止の削減","t":"可動率改善","y":13534,"d":"箱詰めが終わった製品をシリンダーで押してストアに投入していた。シリンダーの前進～後退まで５秒、その間、次の空箱をセットできずに手待ち発生。シリンダーを外して手でストアに投入してもらったところ、３秒でストアに投入し、すぐに次の空箱をセットすることができた。停止時間日当り1.4分の短縮、年間13,534円の労務費低減。"},{"id":"CT-3004","l":"douji","k":"バリスリ","s":"両頭グラインダー","n":"サイクルタイム短縮","t":"CT改善","y":227000,"d":"2箇所のバリスリ作業を行う為、手作業時間が長い。両頭グラインダーにガイドを設置し、2箇所同時にバリスリが出来るようにした結果、1,400s/日短縮、年間で227,000円労務費削減できました。"},{"id":"CT-3009","l":"douji","k":"切削","s":"切削機","n":"サイクルタイム短縮","t":"サイクルタイム短縮改善","y":682000,"d":"ドリルが貫通する下に台を設置し､フタバリをドリルと台で挟みながら穴あけすることで加工と同時にフタバリを製品から除去した｡作業時間が70分短くなり年間で682,000円の労務費削減ができた｡"},{"id":"CT-3019","l":"douji","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":418000,"d":"細い配管では切粉が流れず手作業で除去していたため、配管の径を太くして流量と勢いを上げ、切粉を自動で除去できるようにした。結果、2,580秒/日、年間で418,000円労務費削減できました。"},{"id":"CT-4004","l":"douji","k":"機械加工","s":"ボール盤","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":116928,"d":"人がネック工程となっているラインだった為、作業の観察を実施しました。最終工程で人が前工程の加工部分の検査を行い、その後設備へワークを取り付けて起動スイッチを入れていました。手作業を減らす為に、検査治具へセンサーを取り付け、検査治具へセットすると同時に起動が入るよう改善しました。結果1つの手作業を無くす事ができ0.8秒/回短縮出来ました。日当たり12分稼働時間が短縮でき、年間116,928円労務費削減出来ました。"},{"id":"CT-4009","l":"douji","k":"機械加工","s":"プレス機","n":"CT短縮","t":"CT改善","y":65000,"d":"起動スイッチが遠く、起動入れるのに時間が掛かっていた。そこで、エリアセンサーから手が抜けたら起動が入るように改善した。結果、400s/日短縮、年間で65,000円労務費削減できました。"},{"id":"CT-4011","l":"douji","k":"機械加工","s":"旋盤","n":"CTバラつきの削減","t":"CT改善","y":102000,"d":"作業者がワークを取り出してから、手動でエアーブロー作業を実施していたので、自動エアーブローを設置し、手作業時間短縮。結果、630秒/日短縮、年間で102,000円労務費削減できました。"},{"id":"CT-4017","l":"douji","k":"機械加工","s":"卓上ボール盤","n":"手作業時間短縮","t":"サイクルタイム改善","y":116000,"d":"設備台数が多く、手作業時間が長い。手作業を減らす。一回当たり1.4秒サイクルタイムが短縮され、年間116,000円労務費削減出来ました。"},{"id":"CT-4018","l":"douji","k":"機械加工","s":"検査機","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":409248,"d":"設備の台数が多く、人の手作業が多く発生していました。その中で検査工程が2台あり、各工程でネジ部分の未加工とバリ残りを検査していました。取り付けの姿勢が類似している事から、1台で2つの項目を検査出来る設備へ変更し、１工程分の手作業を無くしました。結果1.2秒/回短縮出来ました。日当たりで42分稼働時間が短縮でき、年間で409,248円労務費削減出来ました。"},{"id":"CT-4025","l":"douji","k":"機械加工","s":"マシニングセンタ","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":77952,"d":"加工設備がネック工程となっており、起動後の動作として扉が閉まった後にワークをクランプしていました。プログラムの修正を行い、扉閉めとワークのクランプを同時に行う事で、マシンタイムは51秒/回から48.8秒/回に短縮出来ました。日当たり8分稼働時間が短縮でき、年間77,952円労務費削減出来ました。"},{"id":"CT-4026","l":"douji","k":"機械加工","s":"マシニング","n":"手待ち時間の削減","t":"CT改善","y":98000,"d":"加工完了後、設備の扉が開いてからアンクランプしている為、手待ちが発生していた。扉を開きながらアンクランプするように変更したことで、手待ち時間1.2ｓ/回短縮され、年間で98,000円労務費低減できました"},{"id":"CT-4031","l":"douji","k":"機械加工","s":"マシニング","n":"マシンタイム短縮","t":"CT改善","y":121000,"d":"クランプ完了後にテーブルを動かしていたため、待機時間が発生していた。エンジニアリング部と相談し、クランプとテーブル移動を同時に行うようプログラムを変更した。結果、750秒/日短縮、年間で121,000円労務費削減できました"},{"id":"CT-4032","l":"douji","k":"機械加工","s":"マシニング","n":"CT短縮の削減","t":"CT改善","y":81000,"d":"加工完了後、テーブルが前に出てからアンクランプしていた為、手待ちが発生していた。そこで、テーブル移動と同時にアンクランプを行うように変更し、動作を並行化することで無駄な待ち時間を解消した。結果、500秒/日短縮、年間で81,000円労務費削減できました。"},{"id":"CT-5007","l":"douji","k":"","s":"","n":"","t":"サイクルタイム改善","y":116928,"d":"設備の台数が多く、人の作業が多く発生している為、人がネック工程となっていました。その中でも、最終工程の設備で１台の中に３つの設備があり、設備間が狭い事で作業のやりづらさを感じました。手作業時間を短縮する為に、最終工程の設備で面取りと仕上げを同時に加工出来ないか検討し、複合刃具へ変更する事によって、1工程分の手作業を廃止し、3.7秒/回サイクルタイムが短縮出来ました。日当たり12分稼働時間が短縮でき、年間で116,92…"},{"id":"CT-5009","l":"douji","k":"機械加工","s":"旋盤","n":"CT短縮","t":"CT改善","y":282000,"d":"荒引き加工と仕上げ加工で刃物を2本使用していた。エンジニアに相談し、仕上げ加工の刃物1本で加工するように変更。結果、1,740ｓ/日短縮、年間で282,000円労務費削減できました。"},{"id":"可動-1017","l":"douji","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":293000,"d":"ワーク受けに切粉が溜り、除去する為の清掃時間が多い。クーラント配管を設置し、切粉が溜らないようにした。切粉清掃30分/日削減、年間で293,000円労務費削減出来ました。"},{"id":"可動-1034","l":"douji","k":"溶接","s":"自動溶接機","n":"段替時間短縮","t":"可動率改善","y":376000,"d":"段替えを1人から2人作業に変更､さらに担当域作業時間平準化実施｡設備稼働時間が20分短くなり年間で195,000円の労務費削減ができた｡"},{"id":"可動-1045","l":"douji","k":"切断･面取り","s":"切断･旋盤機","n":"品質チェック時間短縮","t":"可動率改善","y":4800,"d":"フットスイッチを利用して設備稼働中にエアブローを実施することにより品質チェック時間を3秒短縮設備稼働時間が0.5分短くなり年間で4,800円の労務費削減ができた｡"},{"id":"可動-1059","l":"douji","k":"外観検査","s":"","n":"停止の削減","t":"可動率改善","y":13534,"d":"5段積みにした製品をシリンダーで押してストアに投入した際、右レーンに投入した製品を一山（5箱）おきに左レーンに移すのが重くて時間がかかる。5箱おきに左右レーンに一箱ずつ直接投入し、5段積みすることにより5段の製品を右レーンから左レーンに移す作業がなくなった。停止時間日当り1.4分の短縮、年間13,534円の労務費低減。"},{"id":"可動-1080","l":"douji","k":"段取り替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":60000,"d":"コッターとライナーを別々にセットしており、各作業に時間がかかっていたが、事前にセット化し一括交換を実施。これにより大幅な作業時間短縮を実現した。結果、6分/日削減、年間60,000円労務費削減できました。"},{"id":"可動-2040","l":"douji","k":"検査","s":"人","n":"設備停止の削減","t":"可動率改善","y":49000,"d":"全数検査で爪高さと爪Rを別々の治具で測定していたため、交換の手間が発生していた。エンジニアリング部と連携し、両方を同時に測定できる専用治具に変更し、作業効率を向上。結果、5分/日削減、年間49,000円労務費削減できました"},{"id":"CT-3001","l":"kyori","k":"転造","s":"転造機","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":211000,"d":"起動スイッチをストライカーへ変更､合わせて位置も変更することにより､手の動かす距離を短くして1.3秒のサイクルタイムを短縮､作業時間が22分短くなり年間で211,000円の労務費削減ができた｡"},{"id":"CT-3006","l":"kyori","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":138000,"d":"エアーガンを複数設備で共有しているため、取りに行く歩行がムダになっていた。そこでエアーガンを専用化し手元化、ブロー時間の短縮をした。結果850s/日短縮、年間で138,000円労務費削減できました。"},{"id":"CT-3008","l":"kyori","k":"機械加工","s":"外観検査","n":"CT短縮","t":"CT改善","y":81000,"d":"ダーマペンが吊り下げ式の為、チェックしにくい。ダーマペンを固定し、簡単に印を付ける事ができるようにした。結果、500s/日短縮、年間で81,000円労務費削減できました。"},{"id":"CT-3011","l":"kyori","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":243000,"d":"歩行時間が長い作業者は、歩行にムダがあることが分かりました。そこで、無駄のない歩行をしている作業者の動画を見てもらい教育を実施することで、歩行にムダのあった作業者もムダのない歩行に合わせることができ、CT遅れを無くした。結果、1,500秒/日短縮、年間で243,000円労務費削減できました。"},{"id":"CT-3022","l":"kyori","k":"組付","s":"組付機","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":390000,"d":"粗材･完成品ラックを作業者に近づけて歩行距離を短縮｡サイクルタイムを1.0秒短縮､作業時間が40分短くなり年間で390,000円の労務費削減ができた｡"},{"id":"CT-3028","l":"kyori","k":"完成品工程","s":"完成品ラック","n":"CTバラつきの削減","t":"CT改善","y":414000,"d":"出荷ストアが作業台から離れており、製品運搬のための移動が作業者の負担となっていた。作業者の声を受け、作業台近くに出荷ストアを増設。動線を考慮し腕の可動範囲内で完結できる構造にしたことで、負担を軽減した。結果、2,550秒/日短縮、年間で414,000円労務費削減できました。"},{"id":"CT-3033","l":"kyori","k":"機械加工","s":"マシニング","n":"マシンタイム短縮","t":"CT改善","y":116000,"d":"扉のシリンダストロークが長すぎなので、実際の作業には小さな間口で十分なため、ストロークを短縮し、最小限の動作で扉が開閉するよう改善した。結果、720秒/日短縮、年間で116,000円労務費削減できました。"},{"id":"CT-4005","l":"kyori","k":"機械加工","s":"マシニング","n":"停止の削減","t":"CT改善","y":130000,"d":"作業者より歩行距離短縮の相談があり、ライン編成を観察したところ、設備間にムダなスペースがあった。設備間を20 ㎝近づける事により、歩行距離が短くなり、歩行時間1ｓ/回短縮。停止時間が800s/日短くなり、年間で130,000円労務費削減できました。"},{"id":"CT-4006","l":"kyori","k":"機械加工","s":"マシニング","n":"歩行短縮","t":"CT改善","y":243000,"d":"号口生産では使用しない設備がライン編成の真ん中にあった為、ラインを回る際にムダな歩行が発生。使用頻度の少ない少量生産の設備を入替え、歩行距離短縮。結果1,500ｓ/日短縮、年間で243,000円労務費削減できました。"},{"id":"CT-4008","l":"kyori","k":"機械加工","s":"フライス","n":"CTバラつきの削減","t":"CT改善","y":243000,"d":"3工程と4工程の設備に距離があり、ムダな歩行が発生していたので、ラインのレイアウトをコの字型に変更し、歩行距離を短縮した。結果、1,500s/日短縮、年間で243,000円労務費削減できました。"},{"id":"CT-4021","l":"kyori","k":"切削","s":"マシニング","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":97000,"d":"当該ラインではサイクルタイム短縮のためのネックとなっていた設備は4工程目の穴明け工程で、マシニングという設備になります。人がラインを1周すると完成品が1個出来る中、設備が加工完了となるのを待っていました。マシンネック解消の為、切削以外の部分で時間短縮できないか機械内部の動作映像をもとにアイテム出しを行い、粗材に対して刃具のアプローチがとても早い段階で速度がゆっくりな切削送りに切り替わっていました。粗材と刃具が接触…"},{"id":"CT-4058","l":"kyori","k":"溶着工程","s":"ロボット","n":"マシンタイム短縮","t":"CT改善","y":146000,"d":"X・Y・Z軸を順番に直線移動していたためマシンタイムが長かった。そこで、3軸同時の斜め移動制御に変更し、移動距離短縮で時間を削減した。結果、900秒/日短縮、年間で146,000円労務費削減できました。"},{"id":"CT-4059","l":"kyori","k":"","s":"","n":"","t":"サイクルタイム改善","y":274000,"d":"ダイカストマシンのＣＴ短縮により、搬送ロボットがダイカストに間に合わなくなりました。ロボットの動きを観察してみると方案処理の動きに無駄があるのに気づき、ロボットのプログラム修正を行い、方案を内側から処理する様に変更して1.9秒短縮出来ました。日当たり28分短縮し、年間効果金額274,000円の労務費低減出来ました。"},{"id":"CT-4061","l":"kyori","k":"機械加工","s":"ロボット","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":116928,"d":"マシンネック工程となっており、ロボットは待機姿勢で加工が完了するのを待っていました。ロボットは加工が完了後、次の動作姿勢になりワークを取りにいきます。待機姿勢を次の動作姿勢にする事により、移動距離を短縮しました。結果サイクルタイムが0.6秒短縮出来ました。日当たり12分稼働時間が短縮でき、年間116,928円労務費削減出来ました。"},{"id":"CT-5006","l":"kyori","k":"機械加工","s":"ボール盤","n":"停止の削減","t":"CT改善","y":39000,"d":"刃物の抜け位置が長くムダな距離があったので、抜け位置を10mm短くした。結果、240s/日短縮、年間で39,000円労務費削減できました"},{"id":"可動-1002","l":"kyori","k":"機械加工","s":"全体","n":"停止の削減","t":"可動率改善","y":117000,"d":"課全体で共有している掃除道具を取りに行くのに、歩行の距離が長い。必要な掃除道具をライン横に置く事で歩行距離をなくし、歩行時間2分/回が0分/回、4Ｓ時間12分/日短縮になり、年間で117,000円労務費削減できました。"},{"id":"可動-1024","l":"kyori","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":20000,"d":"段取り替え作業をする際に、必要な工具を置場まで取りに行っていた。必要な工具をあらかじめセットし、手元化をした。段取り替え作業が2分/日短縮され、年間で20,000円労務費削減出来ました。"},{"id":"可動-1027","l":"kyori","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":146000,"d":"段取り替え時の清掃でエアーガンが近くになく、隣のラインまで取りに行く必要があり歩行のムダが発生していた。そこで作業ポイント付近にエアーガンを新設し、すぐ手が届く場所に設置することでムダな移動を解消した。結果、15分/日削減、年間146,000円労務費削減できました。"},{"id":"可動-1037","l":"kyori","k":"機械加工","s":"刃具交換","n":"停止の削減","t":"可動率改善","y":146000,"d":"刃具交換時、必要な工具を工具置場まで取りに行き、返却する手間があり無駄な歩行が発生していた。そこで、工具を専用ツールスタンドに常備し手元化。歩行の手間がなくなり、作業効率が向上した。結果、15分/日削減、年間146,000円労務費削減できました。"},{"id":"可動-1039","l":"kyori","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":87600,"d":"交換刃具を取りに行くのに、歩行距離が長い。置き場を近くに設置して歩行時間の短縮を図る。設備停止時間が、一回当たり25秒短縮され、日当たりで９分。停止時間が短くなり年間で87,600円労務費削減出来ました。"},{"id":"可動-1042","l":"kyori","k":"","s":"","n":"","t":"可動率改善","y":58000,"d":"測定台の位置をライン外からライン内に移動して歩行距離・歩行時間を短縮した。日当たり6分短縮でき、年間効果金額58,000円の労務費低減が出来ました。"},{"id":"可動-1043","l":"kyori","k":"品質チェック","s":"品質チェック台","n":"品質チェック時間の削減","t":"可動率改善","y":48000,"d":"品質チェック用の残置板が作業場所から離れており、製品の出し入れ時に無駄な歩行が発生していた。そこで、残置板を手元近くに配置することで、移動距離を短縮し作業効率が向上した。結果、5分/日削減、年間48,000円労務費削減できました。"},{"id":"可動-1050","l":"kyori","k":"台車入れ替え","s":"付帯作業","n":"停止の削減","t":"可動率改善","y":107000,"d":"粗材台車の位置がラインから離れていたため、作業者が材料を取りに行く際に長い距離を移動する必要があった。粗材台車の位置をラインの近くに変更。歩行距離と移動時間を大幅に削減した。結果、11分/日削減、年間107,000円労務費削減できました。"},{"id":"可動-1053","l":"kyori","k":"完成品","s":"人","n":"停止の削減","t":"可動率改善","y":126000,"d":"仕掛けかんばんが手作業で作業者に戻されており無駄な工程が発生していた。そこで、シュートで直接戻す仕組みに変更し、回収・運搬・仕分けを削減した。結果、13分/日削減、年間126,000円労務費削減できました。"},{"id":"可動-1055","l":"kyori","k":"完成品","s":"人","n":"付帯作業の削減","t":"可動率改善","y":59000,"d":"かんばんが高所や奥にあり無駄動作が発生していたので、手元の届く範囲へ移設し、目線と手元の延長上に取り出し口を設けて効率化した。結果、6分/日削減、年間59,000円労務費削減できました。"},{"id":"可動-1060","l":"kyori","k":"外観検査","s":"","n":"停止の削減","t":"可動率改善","y":8133,"d":"タブレット操作をする際に体をひねって手を伸ばし、変な姿勢で行っていた。タブレットの取り付け位置を作業者の手元で正面を向くように変更。日当り50秒の短縮、年間8,133円の労務費低減。"},{"id":"可動-1064","l":"kyori","k":"外観検査","s":"","n":"停止の削減","t":"可動率改善","y":9760,"d":"「外観不良で撥ねている物の内の半分くらいはコイニング作業中に見つけて処理をしている」ということがわかったのでプレス機の前にもダーマペンを設置。不良品処理時の検査台までの歩行が無くなり停止時間日当り１.0分の短縮、年間9,760円の労務費を低減。"},{"id":"可動-1072","l":"kyori","k":"段取り替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":0,"d":"ラム底測定後に前回値を掲示板まで確認しに行く手間があり、時間がかかっていた。前段台車に記入用ボードを設置し、その場で確認できるように改善。掲示板への移動が不要となり、段替え時間を短縮できた。結果、40ｓ/日削減できました。"},{"id":"可動-1073","l":"kyori","k":"段取り替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":0,"d":"銅パイプ交換時、予備の置き場が遠く時間がかかっていたので、銅パイプ掛けを作業場所の近くに設置。移動の手間がなくなり、交換作業をスムーズに行えるようになった。結果、20s/日削減できました。"},{"id":"可動-2032","l":"kyori","k":"刃具交換","s":"セッチング","n":"付帯作業の削減","t":"可動率改善","y":146000,"d":"刃具交換時、ラインにセッチング台がなく隣のラインまで移動して作業していた。そこで、機外横に専用セッチング台を設置し、作業場所を近くに確保。歩行距離を短縮した。結果、15分/日削減、年間146,000円労務費削減できました。"},{"id":"可動-1001","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":95000,"d":"4Sの標準が無い為、4S時間が日によってバラバラだった。4Sの項目、時間、回数を決めることで、時間のバラツキがなくなり、年間で95,000円労務費削減できました。"},{"id":"可動-1003","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":224000,"d":"機内から油が外へこぼれてしまう為、掃除をする時間が長くなっていた。そこで、カバーを設置し油がこぼれないように対策し、結果、4S時間が23分/日削減でき、年間で224,000円の労務費削減出来ました。"},{"id":"可動-1004","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":282000,"d":"タンクのポンプから機内に繋がるホースが破れて、油が床にこぼれて汚れていた。そこで、クーラントホースを新品に交換し、油こぼれを無くした。結果、20分/日削減、年間282,000/円労務費削減できました。"},{"id":"可動-1008","l":"futai","k":"機械加工","s":"専用機","n":"設備停止の削減","t":"可動率改善","y":78000,"d":"切粉がクーラントの流路外に飛散していたので、対策として、ブラケットを設置し、切粉が溜まらないよう改善しました。結果、8分/日削減、年間78,000円労務費削減できました。"},{"id":"可動-1009","l":"futai","k":"機械加工","s":"フライス","n":"停止の削減","t":"可動率改善","y":49000,"d":"治具に隙間があり、溝に切粉が溜まってしまうので、切粉を取り除く作業に長く時間が掛かっていた。そこで、隙間を石膏で埋めて溝を無くすことにより、切粉が流れやすくなり、4S時間を短縮。結果、5分/日削減、年間49,000円労務費削減できました。"},{"id":"可動-1010","l":"futai","k":"材料供給","s":"パーツフィーダー","n":"4S時間の削減","t":"可動率改善","y":97000,"d":"停止要因グラフで4S時間が長いことが判明。隙間からの油漏れが原因と分かり、ガスケットで隙間を埋めて油漏れを防止し、4S時間を短縮しました。結果、10分/日削減、年間97,000円労務費削減できました。"},{"id":"可動-1011","l":"futai","k":"機械加工","s":"マシニング","n":"4S時間の削減","t":"可動率改善","y":107000,"d":"iXacsで停止要因グラフを確認したところ、4S時間が長いことが分かりました。調査すると、クーラントタンク内の切粉除去に時間がかかっていることが判明。そこで、マグネットを使って切粉を除去し、清掃時間を短縮しました。結果、11分/日削減、年間107,000円労務費削減できました。"},{"id":"可動-1013","l":"futai","k":"機械加工","s":"マシニング","n":"設備停止の削減","t":"可動率改善","y":156000,"d":"設備の停止が多い原因を調査したところ、クーラントタンク内の切粉や汚れが溜まりやすく、頻繁に掃除が必要であることが分かりました。そこで、タンクを大きくして流量を増やし、切粉や汚れが溜まりにくくしました。結果、16分削減、年間156,000円労務費削減できました"},{"id":"可動-1014","l":"futai","k":"機械加工","s":"マシニング","n":"設備停止の削減","t":"可動率改善","y":88000,"d":"クーラントタンクの細かい網目に切粉やゴミが詰まり、オーバーフローが頻発し、清掃に時間がかかっていました。そこで、網目を広げることでクーラントの流れを改善し、詰まりを防ぎました。結果、9分/日削減、年間88,000円労務費削減できました。"},{"id":"可動-1015","l":"futai","k":"機械加工","s":"マシニング","n":"設備停止の削減","t":"可動率改善","y":117000,"d":"4S時にシュートの油をスポンジで吸い取る作業が大変だったため、傾斜をつけてクーラントタンクへ流れるホースを設置し、自動で油が流れるようにした。結果、12分/日削減、年間117,000円労務費削減できました。"},{"id":"可動-1016","l":"futai","k":"機械加工","s":"フライス","n":"設備停止の削減","t":"可動率改善","y":321500,"d":"コの字型のワーク受けに切粉が溜まり清掃時間が増えていたため、縦格子状に変更し切粉が溜まらないようにした。これにより、ワーク受けの清掃が不要となった。結果、33分/日削減、年間321,500円労務費削減できました。"},{"id":"可動-1018","l":"futai","k":"機械加工","s":"マシニング","n":"設備停止の削減","t":"可動率改善","y":263000,"d":"切削中に飛散する切粉が周囲を汚し、清掃や点検時の付帯作業が増加していました。カバーの高さを見直すことで切粉の飛散を防止し、清掃作業の負担を大幅に軽減しました。結果、27分/日削減、年間263,000円労務費削減できました。"},{"id":"可動-1019","l":"futai","k":"機械加工","s":"旋盤","n":"4S時間の削減","t":"可動率改善","y":126000,"d":"停止要因別グラフから4S時間が長いと判明。切粉台車の位置ズレにより切粉が飛散し、清掃に手間がかかっていた。そこで、アングルでストッパーを設置し、台車を定位置に固定。飛散がなくなり清掃時間を削減できた。結果、13分/日削減、年間126,000円労務費削減できました"},{"id":"可動-1020","l":"futai","k":"機械加工","s":"マシニング","n":"設備停止の削減","t":"可動率改善","y":58500,"d":"切粉台車がコンベア端にあり、切粉が片寄って1日4回程度の切粉かきが必要だった。そこで、台車の位置をコンベア中央に変更し、切粉が均等に落ちるようにしたことで、作業は1日1回に削減できた。結果、6分/日削減、年間58,500円労務費削減できました。"},{"id":"可動-1021","l":"futai","k":"機械加工","s":"マシニング","n":"設備停止の削減","t":"可動率改善","y":204000,"d":"クーラント配管に切粉が巻き付くため、作業者が定期的に切粉を除去する作業を行っていた。配管側にカバーを設置し、奥の配管へ切粉が巻き付かないようにした。結果、21分/日削減、年間204,000円労務費削減できました"},{"id":"可動-1022","l":"futai","k":"機械加工","s":"フライス","n":"設備停止の削減","t":"可動率改善","y":214000,"d":"クーラントで切粉を流しても治具に切粉が付着し、頻繁に除去作業が必要だった。調査で治具が帯磁していると判明し、磁気抜きを実施。切粉が付きにくくなり、除去作業の手間を解消できた。結果、22分/日削減、年間214,000円労務費削減できました。"},{"id":"可動-1025","l":"futai","k":"","s":"マシニング","n":"停止の削減","t":"可動率改善","y":195000,"d":"段取り替え作業の際、型にワイヤーを掛ける作業を設備を止めてから行っていた。この作業を外段取り作業に変えることで、段取り時間20分/日削減、年間で195,000円労務費削減できました。"},{"id":"可動-1032","l":"futai","k":"鍛造工程","s":"プレス機","n":"段替え時間の短縮","t":"可動率改善","y":117000,"d":"段替え時間が長く、人によるバラツキ（力の差）が大きい。道具を変更しバラツキを無くす。インパクトレンチに変更した事で、停止時間が１回12分短縮。毎日段替えは行う為、月約4時間工数低減。年間で117,000円労務費削減出来ました。"},{"id":"可動-1033","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":116000,"d":"段替え作業で使用する工具が重く、治具交換や締め付け作業に時間と負担がかかっていた。手が滑る危険もあり作業が慎重になっていたため、工具を軽量化。作業負担を軽減し、段替え作業の効率を向上させた。結果、12分/日削減、年間116,000円労務費削減できました。"},{"id":"可動-1034","l":"futai","k":"外観検査","s":"","n":"停止の削減","t":"可動率改善","y":73200,"d":"技能員が始業作業時に毎日ラインを離れて事務所へ行き、ロット管理表を印刷、裁断していた。職制がロット管理表の準備（印刷・裁断）をするようにした。技能員がラインを離れずに済み、停止時間日当り7.5分短縮、年間73,200円の労務費低減。"},{"id":"可動-1042","l":"futai","k":"機械加工","s":"人","n":"検査時間の短縮","t":"可動率改善","y":224112,"d":"停止要因別グラフを確認すると、定期チェックの停止時間が長い事が分かりました。定期チェック作業ではラインの外にある測定台まで歩行し、必要な項目を測定し、またラインへ戻る作業となっています。そこで測定具を手元化した事によって測定台までの歩行時間を低減しました。結果23分/日短縮する事ができ、年間で224,112円労務費削減出来ました。"},{"id":"可動-1046","l":"futai","k":"組付工程","s":"圧入機","n":"停止の削減","t":"可動率改善","y":156000,"d":"部品箱の容量が小さいため、短時間で部品がなくなり補充作業の回数が多く発生。部品箱を大きなものに変更し収容数を増加させたことで、補充の頻度を減らすことができた。結果、16分/日削減、年間156,000円労務費削減できました。"},{"id":"可動-1051","l":"futai","k":"台車の入れ替え","s":"付帯作業","n":"停止の削減","t":"可動率改善","y":116000,"d":"粗材台車の入替えスペースが狭く、車の出し入れに手間と時間がかかっていた。そこで、台車の入替えに十分なスペースを確保することで、出し入れがスムーズになり、作業の手間と時間を削減。結果、12分/日削減、年間116,000円労務費削減できました。"},{"id":"可動-1075","l":"futai","k":"段取り替え","s":"プレス","n":"停止の削減","t":"可動率改善","y":0,"d":"パンチ型固定時、ボルト本数が多く作業に時間がかかっていた。固定ボルトを4本から3本に減らし、段替え作業のスピードアップを実現した。結果、140ｓ/日削減できました。"},{"id":"可動-2001","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":146000,"d":"ATCシャッターが開いたまま加工しており切粉が飛散する為、加工途中で機内の清掃をしていた。加工中は中間シャッターが閉まるようにプログラムを変更し、ATC側に切粉が飛散しないようにした。結果、設備停止時間15分/日削減でき、年間で146,000円労務費削減できました。"},{"id":"可動-2002","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":185000,"d":"切粉が長い為、クーラントで除去出来ず、切粉が溜まっていた。刃物の形状を変更し短い切粉になるようにした為、機内の掃除回数を減らすことができた。結果、19分/日、停止時間が短くなり、年間185,000円労務費削減できました。"},{"id":"可動-2003","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":127000,"d":"切粉を除去するクーラントが低圧のポンプだったので、油が流れる勢いが弱く機内に切粉が残り、掃除をする頻度が多い。そこで、高圧のポンプに変更し勢いよく流れる様にした結果、13分/日削減することができ、年間で127,000円労務費削減できました。"},{"id":"可動-2004","l":"futai","k":"機械加工","s":"人","n":"４S時間の短縮","t":"可動率改善","y":70156,"d":"停止要因別グラフを確認すると、4S・切粉処理時間が長い事が分かりました。作業を観察すると、切粉が入ったカゴを作業者が手作業で交換を行っており、設備によってはやりづらい場所もありました。マグネットコンベアを設置する事によって、切粉が自動で排出されるようになり、切粉カゴの交換作業を無くしました。結果7分/日短縮する事ができ、年間で70,156円労務費削減出来ました。"},{"id":"可動-2006","l":"futai","k":"機械加工","s":"マシニングセンタ","n":"掃除時間の短縮","t":"可動率改善","y":194880,"d":"掃除時間が長く実際の作業を確認すると、定常の掃除時間とは別に、不定期で機内に堆積した切粉を排出する作業が発生していました。スパイラルコンベアーを機内へ設置し、切粉が堆積しない構造にした事により、人による切粉排出作業を廃止しました。改善を行った結果、20分/日短縮する事ができ、年間194,880円労務費削減出来ました。"},{"id":"可動-2009","l":"futai","k":"機械加工","s":"専用機","n":"停止の削減","t":"可動率改善","y":29000,"d":"治具の締め付けボルトが長く、締め付け・取り外しに時間が掛かっていました。そこで、締め付けボルトの長さを短いものに変更し、ボルトの回転数を減らすことで、締め付け・取り外しの時間を短縮。結果、3分/日削減、年間29,000円労務費削減できました。"},{"id":"可動-2012","l":"futai","k":"洗浄工程","s":"洗浄機","n":"付帯作業時間の削減","t":"可動率改善","y":97000,"d":"1日に3回段替えが発生し、治具の交換に時間がかかっていた。エンジニアに相談して治具を多品種仕様に変更した結果、段替え時の治具交換が不要になり、結果、10分/日削減、年間97,000円労務費削減できました。"},{"id":"可動-2013","l":"futai","k":"機械加工","s":"旋盤","n":"設備停止の削減","t":"可動率改善","y":88000,"d":"治具固定のボルトを全て抜いて位置調整をしていたため、ボルトを抜かずに調整できるよう、プレートの穴形状をダルマ穴に変更。これにより、ボルトを緩めるだけでスライド調整が可能になりました。結果、9分/日削減、年間88,000円労務費削減できました。"},{"id":"可動-2019","l":"futai","k":"機械加工","s":"マシニング","n":"刃具交換回数の削減","t":"可動率改善","y":311000,"d":"刃具ごとに寿命が異なり交換の手間が多かったため、寿命の短い刃具を長寿命化できるか検証。同一設備・製品だったため、寿命を長い方に合わせて同時交換が可能となった。結果、32分/日削減、年間311,000円労務費削減できました"},{"id":"可動-2021","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":93000,"d":"刃具交換による停止が多く、調べた結果、チップの寿命が短いため刃具交換回数が多いことが分かった。そこで、刃具寿命の長いチップに交換。交換回数が減ることで、停止時間短縮となり刃具交換時間9.5分/日削減。年間で93,000円労務費削減できました。"},{"id":"可動-2022","l":"futai","k":"機械加工","s":"マシニング","n":"刃具交換回数の削減","t":"可動率改善","y":438000,"d":"刃具の摩耗が早く寿命が短いため、刃具交換が回数が多い。調査でハイス製を使用していたことが判明。エンジニアの助言で超硬製に変更し、刃具寿命が延びて交換頻度を減らすことができた。結果、45分/日削減、年間438,000円労務費削減できました"},{"id":"可動-2023","l":"futai","k":"機械加工","s":"マシニング","n":"刃具交換回数の削減","t":"可動率改善","y":545000,"d":"ドリル中心部の摩耗が早く、頻繁に刃具交換が必要だったため、エンジニアに相談。「シンニング形状」へ変更すると寿命が延びると助言を受け実施。結果、刃具寿命が延び、交換頻度と停止回数が減少した。結果、56分/日削減、年間545,000円労務費削減できました"},{"id":"可動-2024","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":292000,"d":"刃先の摩耗が早く交換頻度が多かったため、エンジニアに相談。刃具角度を鈍角に変更すると切削抵抗が減ると助言を受け、115度から120度に変更。寿命が延び、交換回数は8回/日から4回/日に削減できた。結果、25分/日削減、年間292,000円労務費削減できました"},{"id":"可動-2025","l":"futai","k":"機械加工","s":"マシニング","n":"刃具交換回数の削減","t":"可動率改善","y":341000,"d":"刃具寿命が短く交換頻度が多かったが、刃具の種類は変更不可のため、エンジニアに相談。コーティングを施すことで摩耗や酸化を抑制。耐摩耗・耐熱性が向上し、刃具寿命を大幅に延ばすことができた。結果、35分/日削減、年間341,000円労務費削減できました"},{"id":"可動-2026","l":"futai","k":"機械加工","s":"専用機","n":"停止の削減","t":"可動率改善","y":107000,"d":"チップ取り付け時に高さがバラつき、寸法不良を防ぐための調整に時間がかかっていた。そこで、取り付け前にダイヤルゲージで高さを確認・管理する方法に変更し、毎回の調整作業を不要にして作業効率を向上させた。結果、11分/日削減、年間107,000円労務費削減できました。"},{"id":"可動-2027","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"","y":116000,"d":"設備のズレによる振動で刃具の摩耗や欠けが早まり、交換頻度が増加していた。そこで、始業前点検にズレ確認項目を追加し、毎日点検を実施。これにより設備のズレが防止され、刃具の摩耗トラブルが解消された。結果、12分/日削減、年間116,000円労務費削減できました。"},{"id":"可動-2028","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":126000,"d":"刃具交換時にプログラムを手動で一つずつ操作していたので、ボタン操作が多く手間がかかっていた。エンジニアリング部に依頼し、1回の操作で刃具交換が完了する専用プログラムを作成。作業の手間を削減した。結果、13分/日削減、年間126,000円労務費削減できました"},{"id":"可動-2029","l":"futai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":146000,"d":"刃具交換時のボルト締付けを感覚で行っていたので、適正トルクの調整に時間がかかっていた。そこでトルクドライバーを導入し専用工具化。誰でも毎回同じトルクで締め付けができるようになり、作業の安定と効率化を実現した。結果、15分/日削減、年間146,000円労務費削減できました。"},{"id":"可動-2030","l":"futai","k":"機械加工","s":"旋盤","n":"停止の削減","t":"可動率改善","y":126000,"d":"刃具の突き出し長さや高さをノギスで調整していたため時間がかかっていた。エンジニアリング部の助言で、基準となるセッチングマスターを導入。基準に合わせることで、作業者が一度で正確に取り付けできるようになった。結果、13分/日削減、年間126,000円労務費削減できました。"},{"id":"可動-2033","l":"futai","k":"機械加工","s":"フライス","n":"付帯作業時間の削減","t":"可動率改善","y":78000,"d":"刃具交換時、中間カラーを厚み調整のため複数枚重ねて使用しており、1枚ずつの作業に時間がかかっていた。おこで、必要厚み分を1本のカラーに統合。取付・取外しが簡易化され、作業時間を短縮できた。結果、8分/日削減、年間78,000円労務費削減できました。"},{"id":"可動-2035","l":"futai","k":"機械加工","s":"マシニング","n":"刃具交換時間の短縮","t":"可動率改善","y":119851,"d":"刃具交換時間が長く、刃具交換作業を確認してみると交換に約４分/回かかっていました。さらに刃具の寿命が短い事で交換回数も多い事が分かりました。加工の条件等変更してみたが効果は無く、エンジニアリング部に協力してもらい刃具を再度選定しました。結果刃具の寿命が約2倍になり、交換回数が減った事で停止時間が12.3分/日短縮する事ができ、年間で119,851円労務費削減出来ました。"},{"id":"可動-2036","l":"futai","k":"","s":"","n":"","t":"可動率改善","y":4800,"d":"３号機は日当たり工数が21.0時間で高負荷の為、停止時間も減らしたい。切削油のノズルも固定してあるが、不安定でずれてしまう事もあり、刃具に切削油のかかりが悪くなり持ちも悪くなっていた。その為、定数交換前に交換している時もあった。又、治具も摩耗があるので、切削中にワークが動いてしまい定数まで持たない原因になっていた。そこでノズルを交換してしっかり固定してずれない様に変更した。治具も摩耗があったので一式交換してワークが動かな…"},{"id":"可動-2048","l":"futai","k":"組付","s":"組付機","n":"可動率向上","t":"可動率改善","y":78000,"d":"前工程の収容数を完成品箱数･入数に合わせ、箱の積み重ね作業を廃止したことにより設備停止時間が日当り8分短縮でき、年間で78,000円の労務費削減ができた｡"},{"id":"可動-2059","l":"futai","k":"機械加工","s":"NC旋盤","n":"必要ない作業の廃止","t":"可動率改善","y":175000,"d":"機械を復帰するのに、必要の無い作業もしている。設備停止時間が、一回当たり84秒短縮され、日当たりで18分、停止時間が短くなり年間で175,000円労務費削減出来ました。"},{"id":"CT-3002","l":"kizukai","k":"機械加工","s":"各工程","n":"CTバラつきの削減","t":"CT改善","y":104000,"d":"起動スイッチの高さがバラバラで作業者がやりにくい為、同じ高さに変更。バラツキがなくなり、結果、640ｓ/日短縮、年間で104,000円労務費削減できました。"},{"id":"CT-3003","l":"kizukai","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":127000,"d":"ワークをセットする際、基準ピンに挿してから治具にセットするのがやりにくい為、治具にガイドピンを付け、ワークを気遣いなく取付けできるようにした。結果、780ｓ/日短縮、年間で127,000円労務費削減できました。"},{"id":"CT-3005","l":"kizukai","k":"機械加工","s":"フライス","n":"CTバラつきの削減","t":"CT改善","y":130000,"d":"ワークが払い出される際に、落ちたり斜めになったりして、作業者が取り出しにくい。そこで、払い出しワーク受けの形状を変更し、ワークを取りやすくした。その結果、800s/日短縮、年間で130,000円労務費削減できました。"},{"id":"CT-3010","l":"kizukai","k":"外観検査","s":"人","n":"CTバラつきの削減","t":"CT改善","y":102000,"d":"検査する際に照明が暗く見づらい為、作業者がワークを細かく確認するのに検査時間が長くなっていた。そこで、見やすいライトに変更することで、ワークの状態を一目で確認しやすくなり、CTのバラツキも減らすことができた。その結果、630秒/日短縮、年間で102,000円労務費削減できました。"},{"id":"CT-3020","l":"kizukai","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":162000,"d":"製品の切粉を手作業で除去していたが、クーラント配管を追加して自動で流すようにし、作業者の負担を軽減しました。結果、1,000秒/日短縮、年間で162,000円労務費削減できました"},{"id":"CT-3021","l":"kizukai","k":"機械加工","s":"フライス","n":"CTバラつきの削減","t":"CT改善","y":186000,"d":"製品に切粉が付着し、その都度除去作業が必要だった。原因を調べると、クーラント配管が切粉のたまりやすい部分に適切に当たっていなかった。配管の狙い位置を見直し、切粉を確実に流せるよう改善した。結果、1,150秒/日、年間で186,000円労務費削減できました"},{"id":"CT-3023","l":"kizukai","k":"組付加工","s":"パーツフィーダー","n":"CTバラつきの削減","t":"CT改善","y":91000,"d":"構成部品を箱から取り出す際、位置や向きを目視確認していたため作業にばらつきが発生。未使用の供給設備を活用し、部品が同じ向きで手元に流れるよう改善。結果、60秒/日短縮、年間で91,000円労務費削減できました。"},{"id":"CT-3024","l":"kizukai","k":"組付け工程","s":"ラック","n":"CTバラつきの削減","t":"CT改善","y":91000,"d":"完成品投入時に箱の高さが変わり作業しづらいとの声があったので、昇降機構を導入し、空箱を設置すると自動で高さを調整。常に一定の高さで投入可能となり、作業負担が軽減された。結果、560秒/日短縮、年間で91,000円労務費削減できました。"},{"id":"CT-3026","l":"kizukai","k":"機械加工","s":"フライス","n":"CTバラつきの削減","t":"CT改善","y":126000,"d":"ワークが滑り板で引っ掛かり向きがズレ、作業者の手直しが発生していた。鉄の摩擦や劣化が要因と分かり、滑り板を平滑で錆びにくいステンレスに変更し、滑り性能を改善した。結果、780秒/日短縮、年間で126,000円労務費削減できました"},{"id":"CT-3027","l":"kizukai","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":102000,"d":"傾斜やスピードの影響でワークが落下し、作業者が拾い直す手間が発生していた。作業者の負担軽減のため、L字型ブラケットを設置し、ワークの落下を防止する対策を実施した。結果、630秒/日短縮、年間で102,000円労務費削減できました。"},{"id":"CT-3029","l":"kizukai","k":"機械加工","s":"専用機","n":"CTバラつきの削減","t":"CT改善","y":116000,"d":"厚手の手袋でワークや部品を掴みにくく、滑落や作業遅れが発生していた。慎重な作業が必要で負担も大きかったため、薄手でグリップ性の高いニトリル手袋に変更。指先の感覚が向上し、掴みやすくなりミスが減少した。結果、720秒/日短縮、年間で116,000円労務費削減できました。"},{"id":"CT-3030","l":"kizukai","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":33000,"d":"受け皿に払い出されたワークの位置がバラバラになる為、作業者が取りにくくバラツキが出ていた。そこで、受け皿にガイドピンを設置し、ワークが毎回同じ位置に払い出されるようにした。結果、CTのバラツキがなくなり。200s/日短縮、年間で33,000円労務費削減できました。"},{"id":"CT-3031","l":"kizukai","k":"外観検査","s":"","n":"サイクルタイム改善","t":"サイクルタイム改善","y":67669,"d":"ワークが箱の中でこぼれそうになっているので作業者が1箱につき2回、手で均していた。シュートの傾斜角をきつくしたことでワークの流れに勢いがつき箱の中で散らばるようになり、手で均す必要がなくなった。日当り6.9分の短縮、年間67,669円の労務費低減。"},{"id":"CT-3032","l":"kizukai","k":"手作業","s":"人","n":"サイクルタイム改善","t":"サイクルタイム改善","y":58464,"d":"人がネック工程となっていた為作業を確認すると、切粉を飛ばす為のエアーブローを人が狙って当てていました。作業のやりにくさを感じ、エアーブローBOXを作成しました。ワークの姿勢を気にせずBOXの中へ入れるだけの作業へ変更した結果、手作業時間が0.8秒短縮出来ました。日当たり6分稼働時間が短縮でき、年間58,464円労務費削減出来ました。"},{"id":"CT-4001","l":"kizukai","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":123000,"d":"起動スイッチを押した時に確実に起動されているか、逐一確認をしていたので、CTがバラついていた。起動スイッチが確実に押され、起動したらブザーが鳴るようにした。結果、CT1.0ｓ/回短縮、日当り800ｓ短縮でき、年間123,000円労務費削減できました"},{"id":"CT-4003","l":"kizukai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"CT改善","y":98000,"d":"受けシュートの幅が広く、ワーク脱着がやりづらいのを、シュートの幅を狭くし、設備と作業者を近づけ脱着をやりやすくした。結果、600ｓ/日短縮、年間で98,000円労務費削減できました。"},{"id":"CT-4007","l":"kizukai","k":"機械加工","s":"マシニング","n":"サイクルタイム短縮","t":"CT改善","y":160000,"d":"奥にある設備でのワーク脱着がやりにくいので、奥側にある2台の設備の向きを斜めにすることで、ワーク脱着をやりやすくしました。結果、990ｓ/日短縮、年間で160,000円労務費削減できました。"},{"id":"CT-4013","l":"kizukai","k":"機械加工","s":"フライス","n":"CTバラつきの削減","t":"CT改善","y":182000,"d":"払い出し機能が無い為、CTのバラツキが発生していることが判明。エンジニアリング部の協力で払い出し機能を追加し、ワークの取り出しが自動化され、CTのバラツキを解消。結果、1,120秒/日短縮、年間で182,000円労務費削減できました。"},{"id":"CT-4015","l":"kizukai","k":"手作業","s":"人","n":"サイクルタイム改善","t":"サイクルタイム改善","y":292320,"d":"人がネック工程となっていた為、作業を確認すると加工完了されたワークを取る際にやりづらさを感じました。ワークの姿勢が払い出しの度にバラバラだった為、シュートを取り付けてワークの向き・位置・姿勢を安定させ1秒短縮出来ました。日当たりで30分稼働時間が短縮でき、年間292,320円労務費削減出来ました。"},{"id":"CT-4020","l":"kizukai","k":"","s":"","n":"","t":"サイクルタイム改善","y":195000,"d":"湯面が下がると給湯機が湯をすくう為に移動距離が長くなり、給湯機がダイカストマシンの動きに間に合わなくなりＣＴがバラツク為、頻繁に湯面を確認しに行っていた。10回／日20分あったが湯面センサーを取付けて、アンドンで湯量を確認出来る様にした。年間効果金額195,000円の労務費低減が出来た。"},{"id":"CT-4029","l":"kizukai","k":"機械加工","s":"旋盤","n":"CTバラつきの削減","t":"CT改善","y":233000,"d":"加工後に作業者がブラシを持って手作業でバリ取りを行っていたので、設備内にブラシを設置してワーク搬出時に自動でバリの除去を行えるようにした。結果、1,440秒/日短縮、年間で233,000円労務費削減できました。"},{"id":"CT-4066","l":"kizukai","k":"組付","s":"組付機","n":"サイクルタイム短縮","t":"サイクルタイム短縮改善","y":146000,"d":"構成品を専用レーン設置にて手元化･定点取りだしとすることにより､0.2秒のサイクルタイムを短縮設備稼働時間が15分短くなり年間で146,000円の労務費削減ができた｡"},{"id":"CT-5002","l":"kizukai","k":"機械加工","s":"専用機","n":"停止の削減","t":"CT改善","y":203000,"d":"穴径の能力が無く、全数検査を実施していた。ブッシュを砲金ブッシュからセラミックブッシュへ変更し、摩耗性を上げ設備能力向上。結果、1,250ｓ/日短縮、年間で203,000円労務費削減できました。"},{"id":"CT-5005","l":"kizukai","k":"機械加工","s":"外観検査","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":960000,"d":"外観検査で鋳巣の規格判断に迷い検査時間が長い、品質教育を行い迷い作業をなくす。品質教育を行うことで、迷い作業がなくなりCT２秒短縮。迷い作業がなくなり年間で960,000円労務費削減出来ました。"},{"id":"CT-5008","l":"kizukai","k":"バリスリ","s":"マシニング","n":"サイクルタイム短縮","t":"CT改善","y":321000,"d":"バリスリ作業に多く時間が掛かっていたので、エンジニアに相談し、バリスリ作業を自働化したことで、人の作業を減らすことができました。結果、1,980s/日短縮、年間で321,000円労務費削減できました。"},{"id":"可動-1005","l":"kizukai","k":"機械加工","s":"ボール盤","n":"停止の削減","t":"可動率改善","y":68000,"d":"切粉カゴ交換時、クーラントホースが干渉するため、ホースを短くし干渉を防止。結果、7分/日削減、年間68,000円労務費削減できました。"},{"id":"可動-1006","l":"kizukai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":146000,"d":"複数の設備でエアーガンを共有しており、作業者がエアーガンを取りに行くというムダが発生していたので、エアーガンを各設備に専用化し手元に置いたことで、取りに行く手間を省いた。結果、15分/日短縮、年間で146,000円労務費削減できました。"},{"id":"可動-1007","l":"kizukai","k":"機械加工","s":"フライス","n":"停止の削減","t":"可動率改善","y":20000,"d":"エアーガンのホースが短く、作業者がエアーガンヘ近づいて作業をしていたので、ホースを長くし手元化することで、ムダな歩行をせずに作業を行えるようにした。結果、2分/日削減、年間20,000円労務費削減できました。"},{"id":"可動-1023","l":"kizukai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":170000,"d":"切粉処理、4Sに時間が掛かっていた。切粉回収カゴを改造し4S時間短縮を図る。切粉カゴのサイズを変更し１回当たり26秒短縮され、日当たり20分。停止時間が短くなり年間170,000円労務費削減出来ました。"},{"id":"可動-1026","l":"kizukai","k":"段取り替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":0,"d":"段取り替え作業で設置位置が曖昧なため、目視確認や微調整に時間がかかっていた。テーブルに基準線を引くことで位置が明確になり、迷わずに位置決めできるようになった。結果、"},{"id":"可動-1028","l":"kizukai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":49000,"d":"段替え作業で取り外した部品の置き場が決まっておらず、探す手間や確認作業が発生していた。そこで専用トレイを作成・設置し、部品の置き場を明確化。作業者間での共有がスムーズになり、ムダな手間を解消した。結果、5分/日削減、年間49,000円労務費削減できました。"},{"id":"可動-1029","l":"kizukai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":107000,"d":"L型レンチでは力が入らずネジの締緩作業に時間がかかっていた為、横展報告での意見を参考にT型レンチへ変更。保持しやすく力を入れやすくなり、ネジの締め緩めがスムーズに行えるようになり、作業効率が向上した。結果、11分/日削減、年間107,000円労務費削減できました。"},{"id":"可動-1030","l":"kizukai","k":"段取り替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":0,"d":"1回目のコッター打ち後の空打ち回数が作業者によって異なり、セット完了時間に差が出ていた。空打ち回数を適切な回数に標準化し統一。これにより段取り替え時間が安定した。結果、30秒/日削減できました。"},{"id":"可動-1044","l":"kizukai","k":"品質チェック","s":"品質チェック台","n":"品質チェック時間の削減","t":"可動率改善","y":29000,"d":"品質チェック記録時、手袋を外す手間や紙の重なりで記入が困難だった。そこで、記入用紙を透明なスライド式ケースに入れることで、手袋をしたままでも記入可能となり、作業効率が向上。結果、3分/日削減、年間29,000円労務費削減できました。"},{"id":"可動-1047","l":"kizukai","k":"完成品","s":"付帯作業","n":"停止の削減","t":"可動率改善","y":185000,"d":"部品箱が水平に配置され手作業が必要だったため、ラックに傾斜をつけて自然に箱が流れるよう改善。手間が減り、交換作業がスムーズになった。結果、19分/日削減、年間185,000円労務費削減できました。"},{"id":"可動-1054","l":"kizukai","k":"完成品","s":"人","n":"設備停止の削減","t":"可動率改善","y":214000,"d":"かんばんが重なって置かれていたため、取りミスや確認の手間が発生。専用ホルダーを作成し、傾斜と仕切りを工夫して1枚ずつしか取れない構造に改善した。結果、22分削減、年間214,000円労務費削減できました"},{"id":"可動-1065","l":"kizukai","k":"外観検査","s":"","n":"停止の削減","t":"可動率改善","y":10996,"d":"台車を定位置に止めるときに曲がりながらの位置合わせが一発でできなくて切り返しをしていた。レイアウトを変更して停止位置に直進で行けるようになり、また、停止位置にアングルでストッパーを設置したことにより切り返しの位置合わせがなくなった。日当り67.6秒の短縮、年間10,996円の労務費低減。"},{"id":"可動-1074","l":"kizukai","k":"段取り替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":0,"d":"圧型をハンマーに入れる際、クレーン位置の調整に時間が掛かっていたため、ハンマー側に白テープで目安線を引いた。これにより位置が一目で分かり、調整時間を短縮できた。結果、20ｓ/日削減できました。"},{"id":"可動-1077","l":"kizukai","k":"段取り替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":0,"d":"段替え作業時、圧型の位置決めに細かい調整が必要で時間がかかっていた。ソーブロックに基準ラインを引き、取付位置を明確化。細かい調整が不要となり、段取り時間を短縮できた。結果、30ｓ/日削減できました。"},{"id":"可動-1079","l":"kizukai","k":"段取り替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":0,"d":"コッターセット時に深さや位置が分かりづらく、調整に時間がかかっていた。事前にコッターへ目安線を引くことで、位置決めが一目で分かるようになり、調整や確認、やり直しを削減できた。結果、2分/日削減できました。"},{"id":"可動-1081","l":"kizukai","k":"段替え","s":"ハンマー","n":"停止の削減","t":"可動率改善","y":0,"d":"圧型の取付位置決めでズレや迷いが多く、時間がかかっていた。作業者からも簡単に取り付けたいとの相談があったため、圧型横に目安ラインを設置。誰でも迷わず素早く正確に位置決めできるよう改善した。結果、20ｓ/日削減できました。"},{"id":"可動-2007","l":"kizukai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":107000,"d":"共通刃物を使用しているが、各品番により工具長が違う為、その都度、補正を修正しているので伝替え時間に時間がかかる。そこで、共通の補正ナンバーから品番毎に調整出来るように補正ナンバーを追加し、切り替えるだけで出来るようにした。結果、11分/日削減。年間107,000円労務費削減できました。"},{"id":"可動-2010","l":"kizukai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":29000,"d":"治具の締付ボルトのサイズがバラバラなので、締付回転にムラがあり時間が掛かっていた。そこで、締め付けボルトの長さ統一、ボルトの締付回転数を一定にし、締め付け・取り外しの調整する時間を無くした。結果、3分/日削減、年間29,000円労務費削減できました。"},{"id":"可動-2014","l":"kizukai","k":"溶接","s":"溶接機","n":"段替時間短縮","t":"可動率改善","y":156000,"d":"ボルト専用穴から長穴タイプに変更、ボルトから蝶ねじに変更やりやすくした段替時間が16分短縮でき、年間で156,000円の労務費削減ができた｡"},{"id":"可動-2015","l":"kizukai","k":"段取り替え","s":"付帯作業","n":"設備停止の削減","t":"可動率改善","y":39000,"d":"ストアが長く移動が大回りになっていたため、短くして小回りが利くようにし、移動をしやすくした。結果、4分/日削減、年間39,000円労務費削減できました。"},{"id":"可動-2034","l":"kizukai","k":"機械加工","s":"マシニング","n":"停止の削減","t":"可動率改善","y":290000,"d":"荒引きと仕上げ加工で2本の刃物を使用していたため、交換頻度が多かった。仕上げ用刃物1本での加工に変更。荒引き刃物を廃止し、1本化により交換頻度を削減できた。結果、30分/日削減、年間290,000円労務費削減できました。"},{"id":"可動-2037","l":"kizukai","k":"検査","s":"Rゲージ","n":"停止時間の削減","t":"可動率改善","y":292000,"d":"爪R検査を実施する際に、良否判定に迷い作業があったので、Rゲージに刻印を入れて良否判定を見える化をした。結果、設備停止時間30分/日削減され、年間292,000円労務費削減できました。"},{"id":"可動-2042","l":"kizukai","k":"品質チェック","s":"付帯作業","n":"品質チェック時間の削減","t":"可動率改善","y":49000,"d":"ネジの測定ゲージは手で直接回していたため扱いにくく、作業に時間がかかっていた。そこで、ハンドルを取り付けることで操作性が向上し、スムーズな作業が可能になった。結果、5分削減、年間49,000円労務費削減できました。"},{"id":"可動-2044","l":"kizukai","k":"品質チェック","s":"ダイヤルゲージ","n":"品質チェック時間の削減","t":"可動率改善","y":68000,"d":"ダイヤルゲージ使用時に毎回調整が必要で作業者の負担が大きく、ミスやばらつきが発生していた。専用ゲージを導入することで調整が不要となり、誰でも簡単に正確な測定が可能になった。結果、7分/日削減、年間68,000円労務費削減できました。"},{"id":"可動-2046","l":"kizukai","k":"品質チェック","s":"人","n":"品質チェック時間の削減","t":"可動率改善","y":88000,"d":"品質チェックで数値を記入していた為、判断や記載に気遣いが必要で、ミスや作業負担が大きかった。◯×記入へ変更することで直感的に判定でき、記入作業が簡素化。判断ミスや誤記入が減り、作業者の負担も軽減。結果、9分/日削減、年間88,000円労務費削減できました。"},{"id":"可動-2057","l":"kizukai","k":"機械加工","s":"円筒研磨機","n":"停止の削減","t":"可動率改善","y":107000,"d":"設備停止時間を少なくするのに、気を使い作業していた。設備停止時間が日当たりで12分停止時間が短くなり、年間で107,000円労務費削減出来ました。"},{"id":"可動-2061","l":"kizukai","k":"外観検査","s":"ワーク整列機","n":"わかりにくさ解消","t":"可動率改善","y":273000,"d":"原位置ランプを追加することにより､設備を再稼働させるのに必要な時間が約10秒まで短縮できた。設備稼働時間が28分短くなり、年間273,000円の労務費削減ができた｡"},{"id":"可動-2063","l":"kizukai","k":"段取り替え","s":"プレス","n":"停止の削減","t":"可動率改善","y":97000,"d":"段替え時に製品が抜けずカシリが発生。上型と下型に隙間が無く、抜型調整が都度必要だった。エンジニアリング部に相談し寸法を見直すことで、製品がスムーズに抜け調整不要となった。結果、10分/日削減、年間97,000円労務費削減できました。"},{"id":"CT-3013","l":"sokudo","k":"バリすり","s":"手作業","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":526176,"d":"人がネック工程となっており、バリすり作業の際にバリの硬さや大きさによって手作業のバラつきが発生していました。使用する工具をヤスリからベルトグラインダーへ変更し、バラつきを軽減し手作業時間を短縮した結果、2.5秒短縮出来ました。日当たり54分稼働時間が短縮でき、年間526,176円労務費削減出来ました。"},{"id":"CT-3014","l":"sokudo","k":"バリスリ","s":"人","n":"CTバラつきの削減","t":"CT改善","y":123000,"d":"リューターが作業台から離れていたため、作業者は手を伸ばして取りに行っていた。そこで、リューターを吊り下げて作業動線を短縮した。結果、800s/日短縮、年間で123,000円分労務費削減できました。"},{"id":"CT-3034","l":"sokudo","k":"機械加工","s":"マシニング","n":"手待ち時間の削減","t":"CT改善","y":260000,"d":"マシンタイムが遅く、加工が終わるのを作業者が待つ手待ち時間が発生していた為、扉のスピードコントローラーを調整し開閉スピードを速くした。結果、CT1,600s/日短縮、年間で260,000円労務削減できました。"},{"id":"CT-3037","l":"sokudo","k":"切削","s":"切削専用機","n":"サイクルタイム短縮","t":"サイクルタイム短縮改善","y":516000,"d":"スピード調整弁を最適化することにより､0.2秒のサイクルタイムを短縮し、設備稼働時間が53分短くなり年間で516,000円の労務費削減ができた｡"},{"id":"CT-4023","l":"sokudo","k":"機械加工","s":"NC旋盤","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":233856,"d":"マシンネック工程となっている為、マシンタイムを短縮する為にプログラム解析を行った。プッシャーと呼ばれる治具でワークがしっかりセット出来ているか確認する動作の中で、移動方法が直線で移動速度が遅い事が分かりました。直線移動を斜め移動へ変更し、速度を速くした事でネック工程のマシンタイムを短縮し結果サイクルタイムが0.7秒短縮出来ました。日当たり24分稼働時間が短縮でき、年間233,856円労務費削減出来ました。"},{"id":"CT-4027","l":"sokudo","k":"機械加工","s":"圧入機","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":526176,"d":"マシンネック工程となっていた為、同様の設備と比較調査した結果、各動作速度に違いがあった。遅い設備を速い設備の動作速度に合わせる事によってマシンタイムが短縮でき、サイクルタイムは2.5秒短縮出来ました。日当たり54分稼働時間が短縮でき、年間526,176円労務費削減出来ました。"},{"id":"CT-4057","l":"sokudo","k":"機械加工","s":"フライス盤","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":315705,"d":"マシンネック工程の為、マシンタイムを短縮する為に加工条件を変更しようとしたが出来なかった。エンジニアリング部に協力してもらい、インバータ制御を追加し早送りの速度を速く出来た事によって、ネック工程を改善し、1.9秒短縮出来ました。日当たり32分稼働時間が短縮でき、年間315,705円労務費削減出来ました。"},{"id":"CT-4063","l":"sokudo","k":"機械加工","s":"完成品コンベアー","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":643104,"d":"溶着完了品を箱詰め工程まで搬送する完成品コンベアーの回転が遅い為、ローダーが溶着完了品を置けず手待ちが発生していた。コンベアーを回転させるモーターの部品を変更し、回転を速くした事でローダーの手待ちが無くなり、1.8秒短縮出来ました。日当たり66分稼働時間が短縮でき、年間643,104円労務費削減出来ました。"},{"id":"CT-4064","l":"sokudo","k":"","s":"","n":"","t":"サイクルタイム改善","y":146000,"d":"ダイカストマシンネックでＣＴ短縮を行ったが、ロボットが間に合わなくなった。ロボットの動きを確認してみるとプレスのエアーブロー遅いことがわかりました。そこでエアーブローのスピードUPし1.0秒短縮しました。その結果として日当たり15分短縮でき、年間効果金額146,000円の労務費低減出来ました。"},{"id":"CT-4065","l":"sokudo","k":"切削","s":"マシニング","n":"サイクルタイム短縮","t":"サイクルタイム短縮改善","y":876000,"d":"切削方法を乾式から湿式に変更し、27秒のサイクルタイムを短縮。設備稼働時間が90分短くなり、年間で876,000円の労務費削減ができた｡"},{"id":"CT-5011","l":"sokudo","k":"機械加工","s":"マシニング","n":"マシンタイム短縮","t":"CT改善","y":65000,"d":"マシンタイムがネックであったため、エンジニアリング部へ相談。刃物回転数をS900からS1200へ上げる事で、1刃当たりの仕事を増やし、マシンタイムを短縮。結果、400秒/日短縮、年間で65,000円労務費削減できました。"},{"id":"CT-5012","l":"sokudo","k":"機械加工","s":"マシニング","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":67700,"d":"加工時間が長い刃具を発見した、刃具の材質を変更。1個当たり2秒短縮、日当たり1時間6分稼働時間が短縮でき、年間67,700円労務費削減出来ました。"},{"id":"CT-5014","l":"sokudo","k":"機械加工","s":"マシニング","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":70156,"d":"マシンネック工程の為、マシンタイムを短縮する為に加工条件を変更しようとしたが出来なかった。刃物を選定し、使用刃物を1本追加し加工条件を変更した事によって、マシンタイムを短縮でき、ネック工程を改善した事によって2.6秒短縮出来ました。日当たり7分稼働時間が短縮でき、年間70,156円労務費削減出来ました。"},{"id":"可動-2045","l":"sokudo","k":"品質チェック","s":"付帯作業","n":"品質チェック時間の削減","t":"可動率改善","y":49000,"d":"現在使用しているマイクロメータは力加減が必要で測定に時間とばらつきが発生していた。バネ付きタイプに変更することで、一定の圧力で誰でも安定した測定が可能となり、力加減の気遣いが不要に。測定時間が短縮された。結果、5分/日削減、年間49,000円労務費削減できました。"},{"id":"CT-3012","l":"kanri","k":"手作業","s":"人","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":126672,"d":"2直生産ラインとなっており、2名の作業者のサイクルタイムに差がありました。実際の作業のビデオを撮り作業解析を行った結果、手作業や歩行時間の違いがありました。比較動画を見せながら教育を実施し、遅い作業者の作業を改善した結果、設定サイクルタイム通りに作業でき、稼働時間が13分低減出来ました。年間126,672円労務費削減出来ました。"},{"id":"CT-4002","l":"kanri","k":"手作業","s":"人","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":906192,"d":"ヒストグラムにバラつきがある事が分かり、調査すると人による作業時間・確認項目に違いがある事が分かりました。目線カメラを使用し作業者毎に解析を行い、ムダを洗い出し外観確認作業を標準化した結果、サイクルタイムが4.5秒短縮出来ました。日当たり93分稼働時間が短縮でき、年間906,192円労務費削減出来ました。"},{"id":"CT-4019","l":"kanri","k":"手作業","s":"人","n":"サイクルタイム短縮","t":"サイクルタイム改善","y":391708,"d":"ヒストグラムにバラつきがある事が分かり、作業教育や手作業の改善を行ったがバラつきが小さくなりませんでした。そこでペースメーカーを設置し、サイクルタイムに対して作業の進捗状況をランプで可視化し、意識付けを行った結果、サイクルタイムが1.5秒短縮しバラつきも低減出来ました。日当たり40分稼働時間が短縮でき、年間391,708円労務費削減出来ました。"},{"id":"可動-1012","l":"kanri","k":"機械加工","s":"マシニング","n":"設備停止時間短縮","t":"可動率改善","y":68208,"d":"設備停止時間が長い為LSMを活用し、停止内容や作業者の困り事の吸い上げを実施した。そこで切粉が細かく網目が詰まってしまう事が分かりました。対策としてマグネットを設置し細かい切粉を受け、目詰まりを無くした事で稼働時間が7分低減でき、年間で68,208円労務費削減出来ました。"},{"id":"可動-1031","l":"kanri","k":"機械加工","s":"専用機","n":"停止の削減","t":"可動率改善","y":97000,"d":"必要部品が揃っておらず、都度探すムダが発生していた。そこで専用棚を設置し、定位置・ラベルで管理することで、必要部品を簡単に揃えられるようにした。結果、10分/日削減、年間97,000円労務費削減できました。"},{"id":"可動-1035","l":"kanri","k":"手作業","s":"人","n":"停止時間短縮","t":"可動改善","y":73000,"d":"段替え時に端数品を置くことを管理していなかった為に、作業者はラインの外に出て戻していた、ライン内に端数品置き場を設置したことにより、停止時間が7.5分低減出来ました。年間73,000円労務費削減出来ました。"},{"id":"可動-1063","l":"kanri","k":"外観検査","s":"ワーク整列機","n":"点検作業時間短縮","t":"可動率改善","y":28800,"d":"１回/人→１回/日へ設備点検基準を変更し標準化、回数を減らすことで、点検作業時間を3分短縮。設備稼働時間が3分短くなり、年間28,800円の労務費削減ができた｡"},{"id":"可動-1066","l":"kanri","k":"","s":"","n":"","t":"可動率改善","y":345000,"d":"横展活動で卒業報告終了後に両班長に可動率の維持活動として、日々可動率をグラフにプロット・iXacsデータからの資料作成し目標を下回った時はiXacsデータから停止要因を確認し対策、すぐに対策出来ない内容についてはいつまでに対策実施するか記入しています。両番班長の連携もスムーズになり維持出来ています。又、山積みの計画通りに生産も出来ている為、無駄な残業もなくなり、年間効果金額は345,000円の労務費低減出来ました。"},{"id":"可動-2016","l":"kanri","k":"","s":"","n":"","t":"可動率改善","y":292000,"d":"週１回、横展活動報告会を行っています。そこで使用しているのが横展ボードです。横展ボードとは、日々の出来高管理や目標の出来高までの進捗や問題点から対策までの見える化が分かるボードです。その横展ボードを使用し毎週係長が横展活動の報告会を行っています。その中で出来高が悪い日は当然計画外残業がでてしまいます。ですが、横展ボードで日々の管理を見える化した事で課長がしっかりフォローできる為計画外残業が減りました。効果として計画外残業が日…"},{"id":"CT-3025","l":"choko","k":"機械加工","s":"マシニング","n":"CTバラつきの削減","t":"CT改善","y":107000,"d":"ワークが受け皿の丸棒の隙間に引っかかり作業性が悪かった。原因は丸棒同士の隙間にワークが入り込むこと。そこで受け皿の一部を板型に変更し、隙間をなくした。ワークの流れがスムーズになり、引っ掛かりを解消。結果、660秒/日短縮、年間で107,000円労務費削減できました。"},{"id":"可動-1048","l":"choko","k":"付帯作業","s":"粗材ラック","n":"停止時間の低減","t":"可動率改善","y":155904,"d":"その他の停止が多かった為作業者に確認すると、空箱を返却する際に途中で引っ掛かり止まってしまうため、ラインを止めて空箱を流す作業が発生している事が分かりました。そこでラックの下部、側面部へコロコンを追加し、空箱の流れをスムーズにする事で、空箱の引っ掛かりによる途中停止を無くしました。空箱を流す作業が無くなり停止時間が16分/日低減する事ができ、年間155,904円労務費削減出来ました。"},{"id":"可動-1049","l":"choko","k":"完成品","s":"フローラック","n":"停止の削減","t":"可動率改善","y":272000,"d":"完成品箱をラックに流す際、箱がコロコンの途中で止まる為、作業者がライン外に出て手で流す作業が発生。ラックに支えを取付け、コロコンが歪まないように対策。スムーズに流れる様にした。停止時間28分/日低減、年間で272,000円労務費削減できました。"},{"id":"可動-1061","l":"choko","k":"外観検査","s":"","n":"停止の削減","t":"可動率改善","y":202520,"d":"箱詰めシュートのカウンターが反応しない（音が鳴らない）時があり、箱詰め中のワークを数えなおしていた。メッシュベルトを撤去し、カウントミスを無くすことができ、数えなおしが無くなった。日当り20.8分の短縮、年間202,520円の労務費低減。"},{"id":"可動-1067","l":"choko","k":"機械加工","s":"パーツフィーダー","n":"停止要因削減","t":"可動率改善","y":380000,"d":"パーツフィーダーからの材料供給遅れにより、設備停止時間が多い。引っ掛かり防止板を付け、日当たりで39分、停止時間が短くなり年間で380,000円労務費削減出来ました。"},{"id":"可動-1068","l":"choko","k":"鍛造工程","s":"電気加熱炉","n":"停止時間の削減","t":"可動率改善","y":58500,"d":"定尺でない材料が次工程へ搬送される際に引っかかって停止が発生している。搬送装置改善により頻発停止を減らす事が出来た。停止時間が日当たり約６分削減する事ができ、年間58,500円労務費削減出来ました。"},{"id":"可動-1069","l":"choko","k":"","s":"自動溶接機","n":"停止の削減","t":"可動率改善","y":456000,"d":"チューブレーンの幅が広く、チューブ不検知発生。レーンの幅を狭くしてチューブを検知させ、停止の削減を図る。設備停止時間が日当たりで51分短くなり、年間456,000円の労務費削減できた｡"},{"id":"可動-1070","l":"choko","k":"","s":"","n":"","t":"可動率改善","y":955000,"d":"アルミ鋳造後にロボットでプレス機の抜型に搬送してプレスして製品と方案を切り離しているがインサート異常にもいろいろあり製品を抜型に置いた時に抜型にうまく入らない・センサーズレ・センサーの調整ミスでなる・センサーの配線つなぎミスなどがあります。インサート異常がどのくらい発生しているかiXacsで調べたところ、日当たり約120回で120分の停止がありました。そこでインサート異常の原因を、チョコ停ウォッチャーを設備に設置…"},{"id":"可動-1071","l":"choko","k":"切断･面取り","s":"切断･旋盤機","n":"サイクルタイム短縮","t":"可動率向上改善","y":409200,"d":"センサーに付着する洗浄液をエアーブローで吹き飛ばすことによりセンサーの誤判定を無くした｡設備稼働時間が42分短くなり、年間409,200円の労務費削減ができた｡"},{"id":"可動-2058","l":"choko","k":"機械加工","s":"粗材供給装置","n":"設備停止時間の低減","t":"可動率改善","y":155904,"d":"設備停止が多い事から調査をした結果、粗材の供給遅れによる設備停止だと分かりました。振動により粗材を搬送しており、大きさや重さによって振動の強弱の調整を行ったが効果はありませんでした。振動による搬送をコンベアー搬送に変更した事によって供給遅れが減り、停止時間が16分/日低減する事ができ、年間155,904円の労務費削減出来ました。"},{"id":"可動-2060","l":"choko","k":"機械加工","s":"反転装置","n":"設備停止時間の低減","t":"可動率改善","y":292320,"d":"反転装置NGが多かった事から調査した結果、バリが残った状態へワークを取り付けると、正常な姿勢にならない為反転装置NGが発生している事が分かりました。バリ残りを無くす為、ワークの基準部分へエアーブローを取り付け、ワーク脱着時にエアーを吹きバリ残りを無くしました。反転装置NGを無くした結果、停止時間が30分/日低減する事ができ、年間292,320円労務費削減出来ました。"},{"id":"可動-2062","l":"choko","k":"切削","s":"設備間運搬装置","n":"設備停止低減","t":"可動率改善","y":672400,"d":"S字コンベアからI字コンベアへ変更したことにより製品落下による後工程への材料供給遅れがなくなった。設備停止時間が69分短くなり、年間672,400円の労務費削減ができた｡"},{"id":"電力-7001","l":"cn","k":"機械加工","s":"ブロー機","n":"ムダ削減","t":"エアー使用量の改善","y":24800,"d":"エアーブロー作業にて、過剰にエアーブローしていた為にムダな電力が発生していた、省エネ用のノズルを取り付けたことで、エアーの流量を減らすことにより電力量が月当たり104Kwh削減され、年間24,800円の電気使用量を削減出来ました。"},{"id":"電力-7005","l":"cn","k":"機械加工","s":"ブロー機","n":"ムダ削減","t":"エアー使用量の改善","y":158000,"d":"エアーブロー機にて、過剰にエアーブローしていた為にムダな電力が発生していた、エアーの流量を減らすことにより電力量月当たり663Kwh削減され、年間158,000円の電気使用量を削減出来ました。"},{"id":"電力-7015/7016","l":"cn","k":"機械加工","s":"設備全体、マシニング、ボール盤、旋盤、フライス盤、専用機、溶着機、洗浄機、組付け機、プレス機","n":"待機電力量削減","t":"待機電気使用量低減","y":587000,"d":"節電はしていたが、調べるとまだ、多くの消費電力がある事が分かった、休憩時間は非常停止、作業終了は電源BOXから電源を切る。設備ごとに何時切れるかを表示することで、待機電力量月当たり2,458Kwh短縮され、年間587,000円の電気使用量を削減出来ました。"},{"id":"電力-7022","l":"cn","k":"機械加工","s":"NC旋盤","n":"待機電力量削減","t":"待機電気使用量低減","y":155000,"d":"生産の時間が空いている為に、待機電力が発生していた。生産時間を繋げて生産することで、停止時間日当たり24.72Kwh低減され、年間155,000円の電気使用量を削減出来ました。"},{"id":"電力-7023","l":"cn","k":"機械加工","s":"洗浄機","n":"ムダ削減","t":"待機電力使用量の改善","y":16600,"d":"洗浄温度が上がるまでに時間がかかっていた、タンク容量を減らすことにより電力量月当たり68Kwh削減され、年間16,000円電気使用量の削減出来ました。"},{"id":"電力-7024","l":"cn","k":"機械加工","s":"マシニング","n":"停止の削減","t":"待機電気使用量の改善","y":44000,"d":"設備の稼働が止まってもエアーが出たままになっていたため、ムダな待機電力が発生していた、機械が停止したら省エネモードに切り替わるように設定し、待機電力量月当たり186Kwh削減され、年間で44,000円の電気使用量を削減出来ました。"},{"id":"電力-7029","l":"cn","k":"機械加工","s":"ブローチ","n":"ムダ削減","t":"電力使用量の改善","y":37000,"d":"必要が無い時にまでモーターが回転し続けていた、不必要時は回転を抑えることによって、電力量月当たり155Kwh削減され、年間37,000円の電気使用量を削減出来ました。"},{"id":"電力-8007","l":"cn","k":"機械加工","s":"研磨機","n":"停止電力量削減","t":"停止電気使用量低減","y":44800,"d":"機械が停止してから処置していたので設備停止が多くなり停止電力が多くなっていた、設備が止まる前にスマートウォッチに通知させることにより、停止電力量月当たり181Kwh短縮され、年間で44,800円の電気使用量を削減出来ました。"},{"id":"電力-8008","l":"cn","k":"機械加工","s":"マシニング","n":"停止の削減","t":"待機電気使用量の改善事例","y":1920000,"d":"電力横展アイテムリスト:電力№8008改善前は設備が初期設定のままで停止しているにもかかわらず、ポンプ・コンベアーが稼働しておりムダな待機電力を使用していました。改善後は設備を省エネ設定に変え、ポンプ・コンベアーを停止させることにより、ムダな待機電力を低減させることが出来ました。カイゼンGAI #工程機械加工#設備マシニング#狙い停止の削減#上位概念電力横展アイテムリスト:電力№8008要るの？#待機電力…"},{"id":"電力-8009","l":"cn","k":"機械加工","s":"コンプレッサー","n":"待機電力量削減","t":"待機電気使用量低減","y":96000,"d":"ラインの稼働数が減ってもコンプレッサーを入れっぱなしにしていたためムダな待機電力が発生していた、必要な分だけコンプレッサーを稼働させることにより、待機電力量月当たり386Kwh短縮され、年間96,000円電気使用量を削減出来ました。"}];
